class AwsSigV4 {
  static String _hmacHex(List<int> key, String msg) {
    final h = Hmac(sha256, key).convert(utf8.encode(msg)).bytes;
    return _toHex(h);
  }

  static List<int> _hmac(List<int> key, String msg) {
    return Hmac(sha256, key).convert(utf8.encode(msg)).bytes;
  }

  static String _toHex(List<int> bytes) {
    final sb = StringBuffer();
    for (final b in bytes) {
      sb.write(b.toRadixString(16).padLeft(2, '0'));
    }
    return sb.toString();
  }

  static String sha256Hex(String msg) => _toHex(sha256.convert(utf8.encode(msg)).bytes);

  static List<int> signingKey({
    required String secretKey,
    required String dateStamp,
    required String region,
    required String service,
  }) {
    final kDate = _hmac(utf8.encode('AWS4$secretKey'), dateStamp);
    final kRegion = _hmac(kDate, region);
    final kService = _hmac(kRegion, service);
    final kSigning = _hmac(kService, 'aws4_request');
    return kSigning;
  }
}

